def set_budget(budgets, category, amount):
    """Set (or replace) the budget for a category and return the amount."""
    budgets[category] = float(amount)
    return budgets[category]


def category_report(records, budgets=None):
    """Return (category, count, total, over_budget) tuples, highest total first.

    ``over_budget`` is True when ``budgets`` has an entry for the category
    and its summed distance exceeds that budget; otherwise False. Ties break
    alphabetically by category for a stable order. Returns an empty list
    when ``records`` is empty.
    """
    budgets = budgets or {}
    totals = {}
    counts = {}
    for r in records:
        totals[r["category"]] = totals.get(r["category"], 0.0) + r["distance"]
        counts[r["category"]] = counts.get(r["category"], 0) + 1
    ranked = sorted(totals.items(), key=lambda kv: (-kv[1], kv[0]))
    return [
        (category, counts[category], total, _is_over_budget(total, budgets.get(category)))
        for category, total in ranked
    ]


def _is_over_budget(total, budget):
    """Return True when ``budget`` is set and ``total`` exceeds it."""
    return budget is not None and total > budget

